import React, { useState, useEffect } from 'react';
import {
    createBrowserRouter,
    RouterProvider,
  } from "react-router-dom";  
import routeMapper, { Route } from './Utils/routeMapper';

const App: React.FC = () => {
  const [routes, setRoutes] = useState<Route[]>([]);
  const [router, setRouter] = useState<any>();

  console.log(routes);
  console.log(router);

  useEffect(() => {
    setRoutes(routeMapper.getRoutes())
  }, [])

  useEffect(() => {
    setRouter(createBrowserRouter(routes))
  }, [routes])

return (
    <React.StrictMode>
        <RouterProvider router={createBrowserRouter(routeMapper.getRoutes())} />
    </React.StrictMode>
    )
}

export default App
